architect_plan:
{
  "summary": "Implemented case-insensitive username handling by normalizing all usernames to lowercase at the schema, route, and storage levels, and added a startup normalization routine to merge existing accounts that differ only by case.",
  "plan": [
    {
      "step": 1,
      "title": "Normalize usernames in shared schema",
      "description": "Updated `insertUserSchema` in `shared/schema.ts` to transform the `username` field to lowercase using Zod's `.transform()`.",
      "files_affected": [
        "shared/schema.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 2,
      "title": "Normalize username in sharing route",
      "description": "Updated the project sharing route in `server/routes.ts` to lowercase the target username before looking it up in the storage.",
      "files_affected": [
        "server/routes.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 3,
      "title": "Implement username normalization and merge logic",
      "description": "Added `normalizeUsernames` method to `DatabaseStorage` and `FileStorage` to convert existing usernames to lowercase and merge duplicate accounts (transferring project ownership and shares) to solve project visibility issues on mobile.",
      "files_affected": [
        "server/databaseStorage.ts",
        "server/fileStorage.ts",
        "server/storage.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 4,
      "title": "Run normalization on server startup",
      "description": "Updated `server/index.ts` to call `storage.normalizeUsernames()` upon server initialization.",
      "files_affected": [
        "server/index.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 5,
      "title": "Improve mobile login and sharing UI",
      "description": "Added `autoCapitalize=\"none\"` and `autoComplete=\"username\"` to username input fields in `AuthPage.tsx` and `ShareProjectDialog.tsx` to prevent mobile devices from automatically capitalizing the first letter.",
      "files_affected": [
        "client/src/pages/AuthPage.tsx",
        "client/src/components/editor/ShareProjectDialog.tsx"
      ],
      "type": "MODIFY"
    }
  ],
  "acceptance_criteria": [
    {
      "id": "c1",
      "description": "insertUserSchema in shared/schema.ts transforms username to lowercase",
      "how_to_verify": "Read shared/schema.ts and check for .transform(val => val.toLowerCase()) on the username field"
    },
    {
      "id": "c2",
      "description": "POST /api/projects/:id/share route normalizes username to lowercase",
      "how_to_verify": "Read server/routes.ts and verify that username from req.body is lowercased before storage lookup"
    },
    {
      "id": "c3",
      "description": "DatabaseStorage has normalizeUsernames method that merges users",
      "how_to_verify": "Read server/databaseStorage.ts and verify the logic for updating project ownerId and shares during user merge"
    },
    {
      "id": "c4",
      "description": "FileStorage has normalizeUsernames method that merges users",
      "how_to_verify": "Read server/fileStorage.ts and verify the logic for updating project ownerId and sharedWith array during user merge"
    },
    {
      "id": "c5",
      "description": "Server startup routine includes username normalization",
      "how_to_verify": "Read server/index.ts and verify that storage.normalizeUsernames() is called in the startup block"
    },
    {
      "id": "c6",
      "description": "AuthPage username inputs have autoCapitalize='none'",
      "how_to_verify": "Read client/src/pages/AuthPage.tsx and check Input components for autoCapitalize prop"
    },
    {
      "id": "c7",
      "description": "ShareProjectDialog username input has autoCapitalize='none'",
      "how_to_verify": "Read client/src/components/editor/ShareProjectDialog.tsx and check the Input component for autoCapitalize prop"
    },
    {
      "id": "c8",
      "description": "All existing tests and type checks pass",
      "how_to_verify": "Run npm run check"
    }
  ],
  "risks": [
    "Merging users might lead to unexpected project lists if the same person created multiple accounts with different projects.",
    "Database conflicts during normalization if unique constraints are strictly enforced in a way that prevents temporary duplicates (handled by logic check)."
  ]
}
